// @kern-source: app-keyboard:283
export function runHandleKeyboardInput(opts: KeyboardInputDeps, input: string, key: any): void {
  if (isTerminalFocusReport(input)) return;
  if (key?.paste) return;
  // The @-file picker (AtFilePicker) owns ALL keystrokes via its own useInput
  // while open — navigation, accept, cancel, and typing into its filter. The
  // global router must stay out so arrows/Enter/Esc/Tab don't double-fire
  // (e.g. history nav or auto-mode toggle) underneath it. Mirrors how the
  // composer swaps its TextInput out while the picker is up.
  if (opts.atPickerOpen) return;

  const keyName = typeof key?.name === 'string' ? key.name.toLowerCase() : '';
  const globalCtrlInputMap = {
    '\x01': 'a',
    '\x03': 'c',
    '\x05': 'e',
    '\x07': 'g',
    '\x0f': 'o',
    '\x0a': 'j',
    '\x0b': 'k',
    '\x0c': 'l',
    '\x12': 'r',
    '\x14': 't',
    '\x15': 'u',
    '\x17': 'w',
    '\x02': 'b',
    ...(key.ctrl ? { '\x09': 'i' } : {}),
  } as Record<string, string>;
  const globalCtrlInput = globalCtrlInputMap[input] ?? (key.ctrl && keyName ? keyName : input);
  const hasGlobalCtrlSignal = !!key.ctrl || ['\x01', '\x02', '\x03', '\x05', '\x07', '\x0a', '\x0b', '\x0c', '\x0f', '\x12', '\x14', '\x15', '\x17'].includes(input);
  if (opts.btwPanel && (key.escape || input === '\x1b')) {
    try { opts.btwAbortRef.current?.abort(); } catch { /* nothing in flight */ }
    opts.btwAbortRef.current = null;
    opts.setBtwPanel(null);
    return;
  }
  const textInputOwnsReservedShortcut = !opts.statusDashboardOpen && !opts.modelPickerOpen && !opts.cesarPickerOpen && !opts.enginePickerOpen && !opts.reviewEvent && !opts.toolDetailEvent && !opts.slashPickerOpen && (!opts.questionState || !opts.questionState.choices);
  if (hasGlobalCtrlSignal && globalCtrlInput === 'e' && !textInputOwnsReservedShortcut) {
    const nested = opts.nestedCtrlShortcutRef.current;
    if (nested.key === 'e' && Date.now() - nested.at < 120) {
      opts.nestedCtrlShortcutRef.current = { key: '', at: 0 };
      return;
    }
    opts.nestedCtrlShortcutRef.current = { key: 'e', at: Date.now() };
    opts.ctrlKeyHandledRef.current = true;
    opts.setToolOutputExpanded((prev: boolean) => !prev);
    return;
  }

  if (opts.statusDashboardOpen && !opts.modelPickerOpen && !opts.cesarPickerOpen && !opts.enginePickerOpen && !opts.reviewEvent && !opts.toolDetailEvent && !opts.slashPickerOpen && !opts.questionState) {
    if (key.escape || input === 'q' || input === 'Q' || (key.ctrl && input === '\x03')) {
      opts.setStatusDashboardOpen(false);
      return;
    }
    if (input === 'a' || input === 'A') {
      opts.setStatusDashboardFilter('all');
      return;
    }
    if (input === 'p' || input === 'P') {
      opts.setStatusDashboardFilter('problem');
      return;
    }
    return;
  }

  // ScrollBox keyboard shortcuts (only when fullscreen owns the viewport and no modal is open).
  if (opts.terminalMode === 'fullscreen' && !opts.modelPickerOpen && !opts.cesarPickerOpen && !opts.enginePickerOpen && !opts.reviewEvent && !opts.toolDetailEvent && !opts.slashPickerOpen && !opts.questionState) {
    if (key.shift && key.name === 'pageup') {
      opts.scrollBoxRef.current?.scrollBy(-Math.max(1, Math.floor(opts.currentVisibleRowBudget / 2)));
      return;
    }
    if (key.shift && key.name === 'pagedown') {
      opts.scrollBoxRef.current?.scrollBy(Math.max(1, Math.floor(opts.currentVisibleRowBudget / 2)));
      return;
    }
    if (key.name === 'home') {
      opts.scrollBoxRef.current?.scrollTo(0);
      return;
    }
    if (key.name === 'end') {
      opts.scrollBoxRef.current?.scrollToBottom?.();
      return;
    }
  }

  const normalizedCtrlInputMap = {
    '\x01': 'a',
    '\x03': 'c',
    '\x05': 'e',
    '\x07': 'g',
    '\x0f': 'o',
    '\x0a': 'j',
    '\x0b': 'k',
    '\x0c': 'l',
    '\x12': 'r',
    '\x14': 't',
    '\x15': 'u',
    '\x17': 'w',
    '\x02': 'b',
    ...(key.ctrl ? { '\x09': 'i' } : {}),
  } as Record<string, string>;
  const normalizedCtrlInput = normalizedCtrlInputMap[input] ?? (key.ctrl && keyName ? keyName : input);
  const hasCtrlSignal = !!key.ctrl || ['\x01', '\x02', '\x03', '\x05', '\x07', '\x0a', '\x0b', '\x0c', '\x0f', '\x12', '\x14', '\x15', '\x17'].includes(input);
  if (hasCtrlSignal && normalizedCtrlInput) {
    const nested = opts.nestedCtrlShortcutRef.current;
    if (nested.key === normalizedCtrlInput && Date.now() - nested.at < 120) {
      opts.nestedCtrlShortcutRef.current = { key: '', at: 0 };
      return;
    }
  }

  const action = resolveKeyboardInput({
    input, key,
    textInputActive: !opts.modelPickerOpen && !opts.cesarPickerOpen && !opts.enginePickerOpen && !opts.reviewEvent && !opts.toolDetailEvent && !opts.slashPickerOpen && (!opts.questionState || !opts.questionState.choices),
    modelPickerOpen: opts.modelPickerOpen, cesarPickerOpen: opts.cesarPickerOpen, slashPickerOpen: opts.slashPickerOpen, enginePickerOpen: opts.enginePickerOpen,
    reviewEventOpen: !!opts.reviewEvent,
    toolDetailOpen: !!opts.toolDetailEvent,
    questionState: opts.questionState, questionChoiceIndex: opts.selectedChoiceIndex, questionOtherActive: opts.questionOtherActive,
    updateInfo: opts.updateInfo,
    replState: opts.replState, runningJobCount: opts.jobManager.running().length,
    inputValue: opts.inputValue, inputHistory: opts.inputHistory, historyIndex: opts.historyIndex,
    planModeQueued: opts.planModeQueued, autoModeQueued: opts.autoModeQueued, activePlanState: opts.activePlanRef.current?.state ?? null,
    planApprovalIndex: opts.planApprovalIndex,
    outputBlockCount: opts.outputBlocks.length,
    commands: opts.allSlashCommands,
    engineIds: opts.availableEngines,
    fileRailFocused: opts.fileRailOpen && opts.inputValue.trim().length === 0,
    fileRailExpanded: opts.fileRailExpandedPath !== null,
    executionRailFocused: opts.executionRailOpen && opts.inputValue.trim().length === 0,
    liveToolStreamCount: Object.keys(opts.liveToolStreamsRef.current ?? {}).length,
  });

  switch (action.type) {
    case 'none': return;
    case 'exit': process.exit(0); return;
    case 'resolveChoice':
      opts.questionState.resolve(action.choiceKey);
      opts.setQuestionState(null); opts.setQuestionAnswer('');
      opts.setSelectedChoiceIndex(0); opts.setQuestionOtherActive(false); return;
    case 'cancelChoice':
      opts.questionState.resolve('n');
      opts.setQuestionState(null); opts.setQuestionAnswer('');
      opts.setSelectedChoiceIndex(0); opts.setQuestionOtherActive(false); return;
    case 'moveChoice':
      opts.setSelectedChoiceIndex(action.index); return;
    case 'enterOther': {
      // Seat the cursor on the __other row so the inline editor renders even
      // when Other was picked by its number (instant), not by arrowing to it.
      // No __other row → nothing to edit; don't enter Other mode (else the hint
      // would wrongly flip to "Esc returns to options").
      const _otherIdx = Array.isArray(opts.questionState?.choices)
        ? opts.questionState.choices.findIndex((c: any) => c && c.key === '__other')
        : -1;
      if (_otherIdx < 0) return;
      opts.setSelectedChoiceIndex(_otherIdx);
      opts.setQuestionOtherActive(true); opts.setQuestionAnswer(''); return;
    }
    case 'exitOther':
      opts.setQuestionOtherActive(false); opts.setQuestionAnswer(''); return;
    case 'swallow': return;
    case 'ghostComplete':
      opts.setInputValue(opts.inputValue + action.ghost + ' ');
      return;
    case 'togglePlanQueued':
      opts.setPlanModeQueued((prev: boolean) => !prev); return;
    case 'toggleAutoQueued':
      const nextAutoModeQueued = !opts.autoModeQueued;
      opts.setPlanModeQueued(false);
      opts.setPersistentAutoMode(nextAutoModeQueued);
      opts.dispatch({
        type: 'info',
        message: nextAutoModeQueued
          ? 'AUTO ON by default. Plain tasks may self-escalate through Cesar. Ctrl+A toggles it off.'
          : 'AUTO OFF by default.',
      } as any);
      return;
    case 'submit':
      opts.handleSubmit(action.value); return;
    case 'planControl':
      // Swallow the Enter/key so PromptTextInput does not insert it
      // into the composer after we route the approval.
      opts.ctrlKeyHandledRef.current = true;
      opts.setPlanApprovalIndex(0);
      if (action.action === 'revise') {
        // Drop the proposal from the live pane but leave the plan in
        // activePlanRef so /cancel on the next turn is a no-op. Pre-fill
        // the composer with a revision prompt; pressing Enter routes the
        // message to Cesar, who (per session.kern RULE 9) will see the
        // pending plan and ProposePlan again with the user's changes.
        opts.setPendingPlanProposal(null);
        opts.setInputValue('Revise the plan: ');
        opts.dispatch({ type: 'info', message: 'Type your revision and press Enter (Esc clears).' } as any);
        return;
      }
      opts.handleSubmit(action.action === 'approve' ? '/approve' : '/cancel');
      return;
    case 'movePlanApproval':
      opts.setPlanApprovalIndex(action.index); return;
    case 'updateBanner':
      // Route the keyboard shortcut from the in-app update banner.
      // `update` opens the choice prompt; `changelog` jumps straight to
      // the release page; `dismiss` hides the banner and remembers the
      // version so we don't nag again for this release.
      if (action.action === 'update') {
        opts.triggerUpdatePrompt();
      } else if (action.action === 'changelog') {
        try { spawnSync('open', ['https://github.com/KERNlang/agon/releases'], { stdio: 'ignore' }); } catch { /* ignore */ }
      } else {
        opts.dismissUpdateBanner();
      }
      return;
    case 'toggleToolExpand':
      opts.ctrlKeyHandledRef.current = true;
      opts.setToolOutputExpanded((prev: boolean) => !prev); return;
    case 'openToolDetail':
      opts.openLatestToolDetail(); return;
    case 'retryFailedTool':
      opts.draftLatestFailedToolRetry(); return;
    case 'openResults':
      opts.openResultsPager(); return;
    case 'toggleFileRail':
      opts.setExecutionRailOpen(false);
      opts.setFileRailOpen((prev: boolean) => !prev);
      return;
    case 'toggleExecutionRail':
      opts.setFileRailOpen(false);
      opts.setFileRailExpandedPath(null);
      opts.setExecutionRailOpen((prev: boolean) => !prev);
      return;
    case 'toggleLiveToolTail':
      opts.ctrlKeyHandledRef.current = true;
      if (!opts.newestLiveToolStreamId) return;
      opts.setLiveToolTailFrozen((prev: Record<string, boolean>) => ({
        ...prev,
        [opts.newestLiveToolStreamId]: !prev[opts.newestLiveToolStreamId],
      }));
      return;
    case 'fileRailSelectPrev': {
      const files = listFiles();
      const last = Math.max(0, files.length - 1);
      opts.setFileRailSelectedIdx((i: number) => Math.max(0, Math.min(last, i) - 1));
      return;
    }
    case 'fileRailSelectNext': {
      const files = listFiles();
      const last = Math.max(0, files.length - 1);
      opts.setFileRailSelectedIdx((i: number) => Math.min(last, Math.max(0, i) + 1));
      return;
    }
    case 'fileRailToggleExpand': {
      const files = listFiles();
      if (files.length === 0) return;
      const idx = Math.max(0, Math.min(files.length - 1, opts.fileRailSelectedIdx));
      const target = files[idx];
      opts.setFileRailExpandedPath((prev: string|null) => prev === target.path ? null : target.path);
      return;
    }
    case 'fileRailClose':
      opts.setFileRailOpen(false);
      opts.setFileRailExpandedPath(null);
      return;
    case 'executionRailClose':
      opts.setExecutionRailOpen(false);
      return;
    case 'unqueuePlan':
      opts.setPlanModeQueued(false); return;
    case 'unqueueAuto':
      opts.setPersistentAutoMode(false);
      opts.dispatch({ type: 'info', message: 'AUTO OFF by default.' } as any);
      return;
    case 'closeSlash':
      opts.setSlashPickerOpen(false); return;
    case 'closeEnginePicker':
      opts.setEnginePickerOpen(false); return;
    case 'cancelQuestion':
      if (opts.questionState) { opts.questionState.resolve(''); opts.setQuestionState(null); opts.setQuestionAnswer(''); }
      return;
    case 'interrupt':
      opts.interruptActiveRun('Interrupted.', false); return;
    case 'clearInput':
      opts.setInputValue(''); return;
    case 'insertNewline':
      opts.setInputValue((prev: string) => prev + '\n'); return;
    case 'historySet':
      opts.setHistoryIndex(action.index);
      // value is always a string — empty string means "return to blank composer".
      opts.setInputValue(action.value);
      return;
    case 'cancelOrExit':
      opts.handleCancelOrExit();
      return;
  }
}
